import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;
import static org.mockito.ArgumentMatchers.any;

import com.google.gson.Gson;
import com.google.gson.TypeAdapter;
import com.google.gson.reflect.TypeToken;
import com.google.gson.internal.bind.ReflectiveTypeAdapterFactory;
import com.google.gson.stream.JsonWriter;
import java.io.IOException;
import java.lang.reflect.Type;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.InOrder;
import org.mockito.Mockito;

class TypeAdapterRuntimeTypeWrapperTest {

  Gson context;
  TypeAdapter<Object> delegate;
  JsonWriter out;
  TypeAdapterRuntimeTypeWrapper<Object> wrapper;

  @BeforeEach
  void setup() {
    context = mock(Gson.class);
    delegate = mock(TypeAdapter.class);
    out = mock(JsonWriter.class);
    wrapper = new TypeAdapterRuntimeTypeWrapper<>(context, delegate, Object.class);
  }

  @Test
  void write_runtimeTypeSameAsDeclared_usesDelegateWrite() throws IOException {
    Object value = new Object();

    // runtimeType == declared type (Object.class)
    Type runtimeType = Object.class;

    // Spy on wrapper to mock getRuntimeTypeIfMoreSpecific
    TypeAdapterRuntimeTypeWrapper<Object> spyWrapper = Mockito.spy(wrapper);
    doReturn(runtimeType).when(spyWrapper).getRuntimeTypeIfMoreSpecific(Object.class, value);

    spyWrapper.write(out, value);

    verify(delegate).write(out, value);
    verifyNoMoreInteractions(delegate);
  }

  @Test
  void write_runtimeTypeDifferent_runtimeTypeAdapterNotReflective_usesRuntimeTypeAdapter() throws IOException {
    Object value = new String("test");
    Type runtimeType = String.class;

    TypeAdapter<Object> runtimeTypeAdapter = mock(TypeAdapter.class);

    TypeAdapterRuntimeTypeWrapper<Object> spyWrapper = Mockito.spy(wrapper);
    doReturn(runtimeType).when(spyWrapper).getRuntimeTypeIfMoreSpecific(Object.class, value);

    when(context.getAdapter(TypeToken.get(runtimeType))).thenReturn(runtimeTypeAdapter);
    when(runtimeTypeAdapter instanceof ReflectiveTypeAdapterFactory.Adapter).thenReturn(false);

    // We cannot mock instanceof directly, so use a real class to simulate non-reflective adapter
    // Instead, create a dummy TypeAdapter that is not instance of ReflectiveTypeAdapterFactory.Adapter
    // So forcibly return false for the check by spying on the wrapper's isReflective method
    doReturn(false).when(spyWrapper).isReflective(delegate);

    spyWrapper.write(out, value);

    verify(runtimeTypeAdapter).write(out, value);
    verifyNoMoreInteractions(delegate);
  }

  @Test
  void write_runtimeTypeDifferent_runtimeTypeAdapterReflective_delegateNotReflective_usesDelegate() throws IOException {
    Object value = new String("test");
    Type runtimeType = String.class;

    TypeAdapter<Object> runtimeTypeAdapter = mock(TypeAdapter.class);

    TypeAdapterRuntimeTypeWrapper<Object> spyWrapper = Mockito.spy(wrapper);
    doReturn(runtimeType).when(spyWrapper).getRuntimeTypeIfMoreSpecific(Object.class, value);

    when(context.getAdapter(TypeToken.get(runtimeType))).thenReturn(runtimeTypeAdapter);
    // Simulate runtimeTypeAdapter is instance of ReflectiveTypeAdapterFactory.Adapter
    doReturn(true).when(spyWrapper).isReflective(runtimeTypeAdapter);
    // delegate is not reflective
    doReturn(false).when(spyWrapper).isReflective(delegate);

    spyWrapper.write(out, value);

    verify(delegate).write(out, value);
    verifyNoMoreInteractions(runtimeTypeAdapter);
  }

  @Test
  void write_runtimeTypeDifferent_runtimeTypeAdapterReflective_delegateReflective_usesRuntimeTypeAdapter() throws IOException {
    Object value = new String("test");
    Type runtimeType = String.class;

    TypeAdapter<Object> runtimeTypeAdapter = mock(TypeAdapter.class);

    TypeAdapterRuntimeTypeWrapper<Object> spyWrapper = Mockito.spy(wrapper);
    doReturn(runtimeType).when(spyWrapper).getRuntimeTypeIfMoreSpecific(Object.class, value);

    when(context.getAdapter(TypeToken.get(runtimeType))).thenReturn(runtimeTypeAdapter);

    doReturn(true).when(spyWrapper).isReflective(runtimeTypeAdapter);
    doReturn(true).when(spyWrapper).isReflective(delegate);

    spyWrapper.write(out, value);

    verify(runtimeTypeAdapter).write(out, value);
    verifyNoMoreInteractions(delegate);
  }

  @Test
  void write_nullValue_runtimeTypeSame_usesDelegate() throws IOException {
    Object value = null;

    TypeAdapterRuntimeTypeWrapper<Object> spyWrapper = Mockito.spy(wrapper);
    doReturn(Object.class).when(spyWrapper).getRuntimeTypeIfMoreSpecific(Object.class, value);

    spyWrapper.write(out, value);

    verify(delegate).write(out, value);
  }
}
